#!/usr/bin/env bash
# Rewrite deps/pins.txt SHAs from local sibling checkouts under SIBLING_ROOT.
# Usage: deps/update_pins.sh
set -euo pipefail
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
SIBLING_ROOT="${SIBLING_ROOT:-${HOME}}"
PINS="$ROOT/deps/pins.txt"
tmp="$(mktemp)"

repos=(shaggy librest libyaml pique libharness libslack libteams libwebmap libnetdiag)

{
  echo "# edgehost dependency pins (P1.0)"
  echo "# Format: <repo>  <git-sha-or-tag>  [# comment]"
  echo "# Regenerated by deps/update_pins.sh on $(date -u +%Y-%m-%dT%H:%MZ)"
  echo "# libsim is Track 0 — leave unpinned until P0.1."
  echo
  for r in "${repos[@]}"; do
    path="$SIBLING_ROOT/$r"
    if [[ -d "$path/.git" ]]; then
      sha="$(git -C "$path" rev-parse HEAD)"
      printf '%-12s %s\n' "$r" "$sha"
    else
      printf '%-12s %s\n' "$r" "<missing at $path>"
    fi
  done
  echo
  echo "# libsim     <pending P0.1>"
} >"$tmp"

mv "$tmp" "$PINS"
echo "Updated $PINS"
cat "$PINS"
